var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"전원, 목표를 고치로 유인하라! 너무 가까이 갈 필요 없다!","JPN":"全員、ターゲットを繭に誘導しろ！　あまり近づく必要はないぞ！","ENG":"All units, lure the target to the cocoon! Be careful not to get too close!","TWN":"全體隊員，用繭引誘目標，別太靠近！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"천천히 물러나면서 튀어나오는 적들만 처리해!","JPN":"ゆっくり後退しつつ、飛び出してくる敵のみを相手にしろ！","ENG":"Fall back and only deal with the ones that pop out!","TWN":"慢慢地退後，只處理視線範圍內的敵人！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"못 해먹겠네, 진짜!","JPN":"ったく、やってられねえ！","ENG":"You've got to be kidding me!","TWN":"討厭，我受夠了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"젠장! 어쩌다 내가 이딴 미친 짓을!","JPN":"クソ！　こんなイカれた作戦に何で俺が！","ENG":"Dammit! How did I even end up here?!","TWN":"該死！我怎麼會做出這種瘋狂的事！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라? 어디 가세요, 제이콥 씨? 그 쪽은 위험하다고요?","JPN":"あれ？　どこに行くんですか、ジェイコブさん？　そちらは危ないですよ？","ENG":"Huh? Where do you think you're going, Jacob? That area's dangerous, you know.","TWN":"咦？你要去哪裡，雅各？那邊很危險的喔～"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"시끄러워. 이래봬도 난 제5방위선의 담당관이야!","JPN":"うるさい。これでも俺は第5防衛線の担当官だ！","ENG":"Shut it! I'm still in charge of the 5th Defense Line!","TWN":"閉嘴，再怎麼說我也是第五防線的負責人！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"네놈들 없이도, 내 살길은 내가 찾아!","JPN":"あんたらなんかいなくても、俺は俺で何とかする！","ENG":"I don't need your help! I'll find my own way out!!","TWN":"不需要你們幫忙，我也能找到活路！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"고치가! 아포리아가 고치에 도달했어!","JPN":"繭が！　アポリアが繭に到達したわ！","ENG":"The cocoon! Aporia's arrived near the cocoon!","TWN":"注意！阿波利亞已經抵達繭的位置！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원, 전장으로부터 이탈합니다! 고치로부터 최대한 떨어지세요!","JPN":"全隊員、戦場から離脱！　繭からできるだけ遠くに離れてください！","ENG":"All units, retreat from the battlefield! Get as far away from the cocoon as possible!","TWN":"全體隊員，撤離戰場！離繭越遠越好！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"목표는 전방의 아포리아 및 다수의 침식체 무리!","JPN":"ターゲットは前方のアポリアおよび多数の侵食体の群れです！","ENG":"Our objective is Aporia and the horde of C.O.s ahead of us!","TWN":"目標為前方的阿波利亞及多個侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"모든 사일로 오픈! 이터니움 반응탄, 서른두 발! 순차 사격 개시!!","JPN":"すべてのサイロを開放！　エタニウム反応弾、32発！　順次射撃開始！！","ENG":"Open all silos! 32 shots of Eternium-reactivated warheads! Fire!!","TWN":"預備發射！永恆之金反應彈，32枚！開始依序發射！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"젠장, 맡겨 달라고!!","JPN":"くそっ、任せておけ！！","ENG":"Dammit, leave it to me!!","TWN":"可惡，交給我吧！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L33_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"소령, 어떻게 됐어? 아포리아는?","JPN":"少佐、どうなった？　アポリアは？","ENG":"Major, how did it go? And Aporia?","TWN":"少校，怎麼樣了？阿波利亞呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아는……","JPN":"アポリアは……","ENG":"Aporia is...","TWN":"阿波利亞……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"마치 시간이 멈춘 것처럼. 공기의 떨림이 멎은 것처럼.","JPN":"まるで時間が止まったかのように。空気の振動が止まったかのように。","ENG":"As if time stood still and the tremor of the air stopped","TWN":"就好像時間靜止，空氣不再流動一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"대원들의 비명소리가 들리지 않는다. 화약의 냄새조차 느껴지지 않는다.","JPN":"隊員の悲鳴が聞こえない。火薬の匂いさえ感じられない。","ENG":"I can't hear the screams of other troops. Nor the smell of gunpowder.","TWN":"我聽不見隊員們的慘叫聲，也聞不到火藥的味道。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 피부가 끓어오를 정도로 느껴지는 살의.","JPN":"それでも感じる、肌が粟立つほどの殺意。","ENG":"Nevertheless, this feeling of murderous intent that makes my skin boil.","TWN":"儘管如此，我仍然感受到了毛骨悚然的殺氣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"틀림없다. 새하얀 절망이 붉게 타오르는 눈으로 이쪽을 응시하고 있다.","JPN":"間違いない。白い絶望が赤く燃え上がる目でじっとこちらを見ている。","ENG":"I'm certain those red, glowing eyes of white despair are staring at me.","TWN":"我很確定。那個白色的絕望正睜著腥紅的雙眼凝視著我。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양!! 피해요!!","JPN":"カリンさん！！　避けてください！！","ENG":"Karin! Watch out!!","TWN":"卡琳！！快閃開！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"크윽!!","JPN":"くっ！！","ENG":"Kgh!!","TWN":"咳呃！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨! 또 저를 감싸려다가!","JPN":"シノンさん！　また私を庇おうとして……！","ENG":"Shiyoung! You're hurt, trying to protect me again!","TWN":"時雨！你又為了保護我而……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"또라니요. 이거 섭섭하게…….","JPN":"いやいや、またじゃありませんよ……","ENG":"Again? That's a little disheartening...","TWN":"又？你這樣說我會難過喔……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"달라, 다르다고요.","JPN":"違いますよ、全然。","ENG":"It's different, I tell you. Different.","TWN":"我告訴你，這次可不一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이번에는, 쓰러지지 않았으니까……","JPN":"今回は、倒れていませんから……","ENG":"Because this time, I didn't faint...","TWN":"因為，這次我沒有倒下……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이번에는 지킬 거니까요.","JPN":"今回は、守ってみせますから。","ENG":"This time, I'm going to protect you.","TWN":"這次，我會守護你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"아하핫! 코메디가 따로 없네, 다 뒈져가는 꼴로 지키긴 뭘 지킨다는 거야!?","JPN":"あははっ！　笑わせてくれるぜ、死にかけの姿で何が守るだ！","ENG":"Ah hah hah! What a joke! How're you supposed to save anyone in that state, huh?!","TWN":"哈哈哈！笑死人，都死到臨頭了，還說什麼要守護別人！？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그 대사 꽤 마음에 들었다고!?","JPN":"でもそのセリフ、グッと来たぜ？","ENG":"But I DO like what you said!","TWN":"但是這個台詞我很喜歡！！"},"stage":{"bg":"SKY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은?","JPN":"あなたは？","ENG":"You are?","TWN":"你是？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하하핫! 여기 있었구나! 델타 세븐!","JPN":"ハハハ！　ここにいたのか！　デルタセブン！","ENG":"Ha ha ha ha! There you are! Delta Seven!","TWN":"哈哈哈！原來在這裡啊！第七三角洲部隊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하마터면 늦었을까 봐, 얼마나 애가 탔는 줄 알아?","JPN":"もう手遅れかもと思って、気が気じゃなかったぜ。","ENG":"Do you know how anxious I was about not arriving on time?","TWN":"差一點趕不上了，你知道我有多著急嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"자 그럼, 어디 쥐새끼처럼 꼬리를 말고 아득바득 살아서 도망쳐 보라고.","JPN":"さあ、ドブネズミのように尻尾を巻いて必死こいて逃げてみな。","ENG":"Now then, why don't you little rats hide your tail and scrabble about, huh?","TWN":"接下來，你們就夾好老鼠尾巴，拼命地逃命吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"여긴 내가 맡을 테니까!","JPN":"ここはオレがやってやるからよ！","ENG":"I'll take care of this!","TWN":"這裡就交給我！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};